using UnityEngine;

/// <summary>Tipo de objecto escalável (P4 — botão de agarrar).</summary>
public enum ClimbableKind
{
    /// <summary>Parede/cipó vertical — exige uma forma com 'canClimb'.</summary>
    Parede,

    /// <summary>Corda — formas com 'canClimb' OU 'canGrab' conseguem agarrar e subir.</summary>
    Corda,

    /// <summary>Escada — formas com 'canClimb' OU 'canGrab' conseguem agarrar e subir.</summary>
    Escada,

    /// <summary>
    /// Cipó de balanço (P8 — Gibão/Babuíno): formas com 'canClimb' OU
    /// 'canGrab' agarram-se (toggle, igual a Corda/Escada) e BALANÇAM em arco
    /// a partir do transform deste objecto (pêndulo), em vez de subir/descer.
    /// Tratado pelo SwingAbility, não pelo ClimbAbility.
    /// </summary>
    CipoBalanco
}

/// <summary>
/// Marca um objecto como escalável (P4): cordas, escadas, paredes/cipós.
/// Colocar num GameObject com Collider2D (pode ser trigger) a cobrir a área
/// escalável. O ClimbAbility procura este componente quando o player segura o
/// botão de AGARRAR e carrega para cima.
///
/// Alternativa sem componente: usar a layer "climbableLayer" do ClimbAbility
/// (tratada como Parede — exige canClimb).
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class ClimbableSurface : MonoBehaviour
{
    public ClimbableKind kind = ClimbableKind.Parede;

    [Tooltip("Multiplicador da velocidade de escalada nesta superfície (ex: corda escorregadia = 0.7). Para CipoBalanco: multiplica a 'força' do balanço (input) e a velocidade angular máxima.")]
    [Min(0.1f)] public float climbSpeedMultiplier = 1f;

    /// <summary>True se a forma "form" pode usar esta superfície: Parede exige canClimb; Corda/Escada/CipoBalanco aceitam canClimb OU canGrab.</summary>
    public bool AllowsForm(AnimalFormData form)
    {
        if (form == null) return false;

        if (kind == ClimbableKind.Parede) return form.canClimb;
        return form.canClimb || form.canGrab;
    }
}
